package main

import (
	"html/template"
	"net/http"
)

var commentTemplate = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
    <title>User Comments</title>
</head>
<body>
    <h1>User Comments</h1>
    <ul>
        {{range .}}
            <li>{{. | safeHTML}}</li>
        {{end}}
    </ul>
</body>
</html>
`))

func main() {
	comments := []string{
		"Hello, this is my comment.",
		"I like this website.",
		"Great work!",
	}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "text/html; charset=utf-8")
		commentTemplate.Execute(w, comments)
	})

	http.ListenAndServe(":8080", nil)
}

func safeHTML(s string) template.HTML {
	return template.HTML(s)
}